/**
 * Master runner: process any FERC Form 1 HTML or XBRL filing through all extractors.
 *
 * Usage:
 *   node run_all_ferc.js <path-to-filing>
 *   node run_all_ferc.js ClecoPowerLlc2023.html
 *   node run_all_ferc.js filings/ClecoPowerLlc2020.xbrl
 *
 * Auto-detects format from extension (.html / .htm → HTML parsers;
 * .xbrl / .xml → XBRL parsers). Detects utility_id, report_year, and
 * company short name; reuses/creates the company folder; runs five schedules.
 */

const fs = require("fs");
const path = require("path");

const fillAbout = require("./fill_about_info.js");
const fillSalesByRate = require("./fill_sales_by_rate_totals.js");
const fillSalesForResale = require("./fill_sales_for_resale.js");
const fillPlantInService = require("./fill_plant_in_service.js");
const fillOmExpenses = require("./fill_om_expenses.js");

const fillAboutXbrl = require("./fill_about_info_xbrl.js");
const fillSalesByRateXbrl = require("./fill_sales_by_rate_totals_xbrl.js");
const fillSalesForResaleXbrl = require("./fill_sales_for_resale_xbrl.js");
const fillPlantInServiceXbrl = require("./fill_plant_in_service_xbrl.js");
const fillOmExpensesXbrl = require("./fill_om_expenses_xbrl.js");

const {
  COMPANY_ALIASES,
  companyFolderName,
  resolveCompanyDir,
  resolveTemplatePath,
  cleanText,
} = require("./lib/company");

const BASE_DIR = __dirname;

const PIPELINE_HTML = [
  {
    key: "about",
    label: "About / contact info",
    template: "about.xlsx",
    filePrefix: "about",
    run: (opts) => fillAbout.fillAboutFromHtml(opts),
  },
  {
    key: "sales_by_rate",
    label: "Sales by rate schedules",
    template: "sales_by_rate.xlsx",
    filePrefix: "sales_by_rate",
    run: (opts) => fillSalesByRate.fillSalesByRateFromHtml(opts),
  },
  {
    key: "sales_for_resale",
    label: "Sales for resale",
    template: "sales_for_resale.xlsx",
    filePrefix: "sales_for_resale",
    run: (opts) => fillSalesForResale.fillSalesForResaleFromHtml(opts),
  },
  {
    key: "plant_in_service",
    label: "Electric plant in service",
    template: "plant_in_service.xlsx",
    filePrefix: "plant_in_service",
    run: (opts) => fillPlantInService.fillPlantInServiceFromHtml(opts),
  },
  {
    key: "om_expenses",
    label: "O&M expenses",
    template: "om_expenses.xlsx",
    filePrefix: "om_expenses",
    run: (opts) => fillOmExpenses.fillOmExpensesFromHtml(opts),
  },
];

const PIPELINE_XBRL = [
  {
    key: "about",
    label: "About / contact info",
    template: "about.xlsx",
    filePrefix: "about",
    run: (opts) =>
      fillAboutXbrl.fillAboutFromXbrl({
        ...opts,
        xbrlPath: opts.htmlPath || opts.xbrlPath,
      }),
  },
  {
    key: "sales_by_rate",
    label: "Sales by rate schedules",
    template: "sales_by_rate.xlsx",
    filePrefix: "sales_by_rate",
    run: (opts) =>
      fillSalesByRateXbrl.fillSalesByRateFromXbrl({
        ...opts,
        xbrlPath: opts.htmlPath || opts.xbrlPath,
      }),
  },
  {
    key: "sales_for_resale",
    label: "Sales for resale",
    template: "sales_for_resale.xlsx",
    filePrefix: "sales_for_resale",
    run: (opts) =>
      fillSalesForResaleXbrl.fillSalesForResaleFromXbrl({
        ...opts,
        xbrlPath: opts.htmlPath || opts.xbrlPath,
      }),
  },
  {
    key: "plant_in_service",
    label: "Electric plant in service",
    template: "plant_in_service.xlsx",
    filePrefix: "plant_in_service",
    run: (opts) =>
      fillPlantInServiceXbrl.fillPlantInServiceFromXbrl({
        ...opts,
        xbrlPath: opts.htmlPath || opts.xbrlPath,
      }),
  },
  {
    key: "om_expenses",
    label: "O&M expenses",
    template: "om_expenses.xlsx",
    filePrefix: "om_expenses",
    run: (opts) =>
      fillOmExpensesXbrl.fillOmExpensesFromXbrl({
        ...opts,
        xbrlPath: opts.htmlPath || opts.xbrlPath,
      }),
  },
];

// ---------------------------------------------------------------------------
// Detection helpers (HTML iXBRL)
// ---------------------------------------------------------------------------

function stripTags(html) {
  return cleanText(String(html || "").replace(/<[^>]+>/g, " "));
}

function grabIxFact(html, concept) {
  const name = concept.startsWith("ferc:") ? concept : `ferc:${concept}`;
  const re = new RegExp(
    `name="${name.replace(/:/g, "\\:")}"[^>]*>([\\s\\S]*?)</ix:`,
    "i"
  );
  const m = html.match(re);
  return m ? stripTags(m[1]) : "";
}

function detectFilingMetaHtml(html, htmlPath) {
  const utilityId =
    grabIxFact(html, "CompanyIdentifier") ||
    grabIxFact(html, "RespondentIdentifier") ||
    grabIxFact(html, "FilerIdentifier") ||
    "";

  const yearRaw = grabIxFact(html, "ReportYear");
  let reportYear = yearRaw ? Number(yearRaw) : null;

  if (reportYear == null || Number.isNaN(reportYear)) {
    const base = path.basename(htmlPath, path.extname(htmlPath));
    const ym = base.match(/(19|20)\d{2}/);
    if (ym) reportYear = Number(ym[0]);
  }

  const respondent =
    grabIxFact(html, "RespondentLegalName") ||
    grabIxFact(html, "EntityName") ||
    "";

  const titleM = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  const title = titleM ? stripTags(titleM[1]) : "";

  return { utilityId, reportYear, respondent, title };
}

function detectFormat(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  if (ext === ".html" || ext === ".htm") return "html";
  if (ext === ".xbrl" || ext === ".xml") return "xbrl";
  // Peek at content
  try {
    const head = fs.readFileSync(filePath, "utf8").slice(0, 2000);
    if (/<html[\s>]/i.test(head) || /ix:nonFraction|ix:nonNumeric/i.test(head)) {
      return "html";
    }
    if (/<xbrl[\s>]/i.test(head) || /xmlns:ferc=/i.test(head)) {
      return "xbrl";
    }
  } catch {
    /* ignore */
  }
  throw new Error(
    `Unrecognized filing format for ${filePath} (expected .html, .xbrl, or .xml)`
  );
}

// ---------------------------------------------------------------------------
// Pipeline
// ---------------------------------------------------------------------------

/**
 * Process one FERC Form 1 filing through all extractors.
 */
function runAllFerc(filingPath, { baseDir = BASE_DIR } = {}) {
  const resolved = path.resolve(filingPath);
  if (!fs.existsSync(resolved)) {
    throw new Error(`Filing not found: ${resolved}`);
  }

  const format = detectFormat(resolved);
  const pipeline = format === "xbrl" ? PIPELINE_XBRL : PIPELINE_HTML;

  let meta;
  if (format === "html") {
    const html = fs.readFileSync(resolved, "utf8");
    meta = detectFilingMetaHtml(html, resolved);
  } else {
    const { loadXbrl, detectXbrlMeta } = require("./xbrl_common");
    const doc = loadXbrl(resolved);
    const m = detectXbrlMeta(doc, resolved);
    meta = {
      utilityId: m.utilityId,
      reportYear: m.reportYear,
      respondent: m.respondent,
      title: "",
    };
  }

  if (!meta.utilityId) {
    console.warn("Warning: utility_id not found; using UNKNOWN");
  }
  if (meta.reportYear == null || Number.isNaN(meta.reportYear)) {
    throw new Error(
      "Could not determine report_year from filing or filename"
    );
  }

  const companyShort = companyFolderName(
    meta.respondent,
    meta.title,
    resolved
  );
  const { companyDir, company, created } = resolveCompanyDir(
    baseDir,
    companyShort
  );

  const utilityId = meta.utilityId || "UNKNOWN";
  const reportYear = meta.reportYear;

  console.log("══════════════════════════════════════════════════");
  console.log(" FERC Form 1 batch extract");
  console.log("══════════════════════════════════════════════════");
  console.log(` Filing:      ${resolved}`);
  console.log(` Format:      ${format.toUpperCase()}`);
  console.log(` Respondent:  ${meta.respondent || "(n/a)"}`);
  console.log(` Utility ID:  ${utilityId}`);
  console.log(` Report year: ${reportYear}`);
  console.log(
    ` Company:     ${company}${created ? " [folder created]" : " [existing folder]"}`
  );
  console.log(` Output dir:  ${companyDir}`);
  console.log("──────────────────────────────────────────────────");

  const results = [];
  const createdFiles = [];
  const errors = [];

  for (const step of pipeline) {
    const templatePath = resolveTemplatePath(baseDir, step.template);
    const outputFileName = `${step.filePrefix}_${utilityId}_${reportYear}.xlsx`;
    const expectedPath = path.join(companyDir, outputFileName);

    process.stdout.write(` → ${step.label} ... `);

    if (!fs.existsSync(templatePath)) {
      const msg = `template missing: ${step.template}`;
      console.log(`SKIP (${msg})`);
      errors.push({ step: step.key, error: msg });
      results.push({
        key: step.key,
        label: step.label,
        ok: false,
        skipped: true,
        error: msg,
      });
      continue;
    }

    try {
      const out = step.run({
        htmlPath: resolved,
        xbrlPath: resolved,
        templatePath,
        baseDir,
        outputFileName,
        companyName: company,
        utilityId,
        reportYear,
      });

      const outputPath = out.outputPath || expectedPath;
      const exists = fs.existsSync(outputPath);
      console.log(exists ? "OK" : "OK (path?)");
      if (exists) createdFiles.push(outputPath);

      results.push({
        key: step.key,
        label: step.label,
        ok: true,
        outputPath,
        result: out,
      });
    } catch (err) {
      const message = err && err.message ? err.message : String(err);
      console.log(`FAIL`);
      console.log(`   ${message}`);
      errors.push({ step: step.key, error: message });
      results.push({
        key: step.key,
        label: step.label,
        ok: false,
        error: message,
      });
    }
  }

  console.log("──────────────────────────────────────────────────");
  console.log(" SUMMARY");
  console.log("──────────────────────────────────────────────────");
  console.log(` Company folder: ${companyDir}`);
  console.log(` Year:           ${reportYear}`);
  console.log(` Utility ID:     ${utilityId}`);
  console.log(` Format:         ${format}`);
  console.log(
    ` Steps ok:       ${results.filter((r) => r.ok).length}/${pipeline.length}`
  );
  if (createdFiles.length) {
    console.log(" Files written:");
    for (const f of createdFiles) {
      console.log(`   • ${path.basename(f)}`);
    }
  }
  if (errors.length) {
    console.log(" Errors:");
    for (const e of errors) {
      console.log(`   • ${e.step}: ${e.error}`);
    }
  }
  console.log("══════════════════════════════════════════════════");

  return {
    filingPath: resolved,
    format,
    companyDir,
    company,
    companyFolderCreated: created,
    utilityId,
    reportYear,
    respondent: meta.respondent,
    results,
    createdFiles,
    errors,
  };
}

function main() {
  const arg = process.argv[2];
  if (!arg) {
    console.error("Usage: node run_all_ferc.js <path-to-html-or-xbrl>");
    console.error("Example: node run_all_ferc.js ClecoPowerLlc2023.html");
    console.error("Example: node run_all_ferc.js filings/ClecoPowerLlc2020.xbrl");
    process.exit(1);
  }

  try {
    const summary = runAllFerc(arg, { baseDir: BASE_DIR });
    if (summary.errors.length) process.exitCode = 1;
  } catch (err) {
    console.error(err.message || err);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

module.exports = {
  runAllFerc,
  detectFormat,
  detectFilingMetaHtml,
  companyFolderName,
  resolveCompanyDir,
  COMPANY_ALIASES,
  PIPELINE_HTML,
  PIPELINE_XBRL,
};

/**
 * Shared utilities for parsing FERC Form 1 XBRL instance documents.
 *
 * Supports classic XBRL fact form:
 *   <ferc:ConceptName contextRef="c-01" unitRef="u-02" decimals="0">123</ferc:ConceptName>
 *
 * Also tolerates alternate prefixes and simple context graphs (duration/instant + segments).
 */

const fs = require("fs");
const path = require("path");
const { cleanText, companyFolderName } = require("./lib/company");

function decodeXmlEntities(s) {
  return String(s || "")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)))
    .replace(/&#x([0-9a-fA-F]+);/g, (_, h) =>
      String.fromCharCode(parseInt(h, 16))
    );
}

function parseNumber(value) {
  let text = cleanText(decodeXmlEntities(value));
  if (!text) return null;
  text = text.replace(/^\([a-z]\)\s*/i, "").trim();
  if (!text) return null;
  const neg = /^\(.*\)$/.test(text);
  const norm = text.replace(/[(),$]/g, "").replace(/,/g, "");
  if (!norm || /[a-zA-Z]/.test(norm)) return null;
  const n = Number(norm);
  if (Number.isNaN(n)) return null;
  return neg ? -n : n;
}

/**
 * Parse contexts from an XBRL instance.
 * @returns {Map<string, object>}
 */
function parseContexts(xml) {
  const contexts = new Map();
  const re =
    /<context\b[^>]*\bid="([^"]+)"[^>]*>([\s\S]*?)<\/context>/gi;
  let m;
  while ((m = re.exec(xml))) {
    const id = m[1];
    const body = m[2];

    const identM = body.match(
      /<identifier\b[^>]*>([\s\S]*?)<\/identifier>/i
    );
    const identifier = identM ? cleanText(decodeXmlEntities(identM[1])) : "";

    let periodType = "unknown";
    let startDate = null;
    let endDate = null;
    let instant = null;
    const instantM = body.match(/<instant>([^<]+)<\/instant>/i);
    if (instantM) {
      periodType = "instant";
      instant = cleanText(instantM[1]);
    } else {
      const startM = body.match(/<startDate>([^<]+)<\/startDate>/i);
      const endM = body.match(/<endDate>([^<]+)<\/endDate>/i);
      if (startM || endM) {
        periodType = "duration";
        startDate = startM ? cleanText(startM[1]) : null;
        endDate = endM ? cleanText(endM[1]) : null;
      }
    }

    const segments = [];
    const segRe =
      /<(?:xbrldi:)?(?:explicitMember|typedMember)\b([^>]*)>([\s\S]*?)<\/(?:xbrldi:)?(?:explicitMember|typedMember)>/gi;
    let sm;
    while ((sm = segRe.exec(body))) {
      const attrs = sm[1] || "";
      const inner = sm[2] || "";
      const dimM = attrs.match(/dimension="([^"]+)"/i);
      const dimension = dimM ? dimM[1].replace(/^ferc:/, "") : "";
      const member = cleanText(
        decodeXmlEntities(inner.replace(/<[^>]+>/g, " "))
      );
      // typedMember often has nested element text like 0-1
      const nested = inner.match(/>([^<]+)</);
      segments.push({
        dimension,
        member: nested ? cleanText(decodeXmlEntities(nested[1])) : member,
        raw: cleanText(decodeXmlEntities(inner)),
      });
    }

    contexts.set(id, {
      id,
      identifier,
      periodType,
      startDate,
      endDate,
      instant,
      segments,
      hasSegment: segments.length > 0,
    });
  }
  return contexts;
}

/**
 * Parse all ferc:* facts from an XBRL instance.
 * @returns {Array<{concept: string, contextRef: string, unitRef: string|null, value: string, numeric: number|null}>}
 */
function parseFacts(xml) {
  const facts = [];
  // Require ferc: prefix so we do not scan the entire non-FERC XML tree.
  // Form: <ferc:ConceptName contextRef="c-01" ...>value</ferc:ConceptName>
  const re =
    /<ferc:([A-Za-z][A-Za-z0-9_]*)\b([^>]*)>([\s\S]*?)<\/ferc:\1>/g;
  let m;
  while ((m = re.exec(xml))) {
    const concept = m[1];
    const attrs = m[2] || "";
    // Facts always carry contextRef; skip domain/member placeholders without one
    if (!/\bcontextRef=/.test(attrs)) continue;

    const ctxM = attrs.match(/\bcontextRef="([^"]+)"/i);
    const unitM = attrs.match(/\bunitRef="([^"]+)"/i);
    const raw = cleanText(decodeXmlEntities(m[3].replace(/<[^>]+>/g, " ")));
    facts.push({
      concept,
      contextRef: ctxM ? ctxM[1] : "",
      unitRef: unitM ? unitM[1] : null,
      value: raw,
      numeric: parseNumber(raw),
    });
  }
  return facts;
}

/**
 * Load and index an XBRL instance document.
 */
function loadXbrl(filePath) {
  const xml = fs.readFileSync(filePath, "utf8");
  const contexts = parseContexts(xml);
  const facts = parseFacts(xml);

  // Index: concept → facts[]
  const byConcept = new Map();
  for (const f of facts) {
    if (!byConcept.has(f.concept)) byConcept.set(f.concept, []);
    byConcept.get(f.concept).push(f);
  }

  // Identify primary duration context (report year, no segment)
  const durationNoSeg = [...contexts.values()].filter(
    (c) => c.periodType === "duration" && !c.hasSegment
  );
  // Prefer longest calendar-year span ending in report year
  durationNoSeg.sort((a, b) => {
    const ay = a.endDate || "";
    const by = b.endDate || "";
    return by.localeCompare(ay);
  });

  const primaryDuration =
    durationNoSeg.find((c) => {
      if (!c.startDate || !c.endDate) return false;
      // full year roughly
      return c.startDate.slice(5) === "01-01" && c.endDate.slice(5) === "12-31";
    }) || durationNoSeg[0] || null;

  const reportYearFromCtx = primaryDuration?.endDate
    ? Number(primaryDuration.endDate.slice(0, 4))
    : null;

  // Prior year duration (for O&M previous year)
  const priorDuration =
    durationNoSeg.find((c) => {
      if (!primaryDuration || !c.endDate || !primaryDuration.endDate) return false;
      const y = Number(c.endDate.slice(0, 4));
      const py = Number(primaryDuration.endDate.slice(0, 4));
      return (
        y === py - 1 &&
        c.startDate &&
        c.startDate.slice(5) === "01-01" &&
        c.endDate.slice(5) === "12-31"
      );
    }) || null;

  // Instant contexts: end of report year / beginning (prior year-end)
  const instants = [...contexts.values()].filter(
    (c) => c.periodType === "instant" && !c.hasSegment
  );
  const eoyInstant =
    instants.find(
      (c) =>
        reportYearFromCtx &&
        c.instant === `${reportYearFromCtx}-12-31`
    ) ||
    instants
      .filter((c) => c.instant && c.instant.endsWith("-12-31"))
      .sort((a, b) => (b.instant || "").localeCompare(a.instant || ""))[0] ||
    null;

  const boyInstant =
    (reportYearFromCtx &&
      instants.find((c) => c.instant === `${reportYearFromCtx - 1}-12-31`)) ||
    null;

  return {
    filePath: path.resolve(filePath),
    xml,
    contexts,
    facts,
    byConcept,
    primaryDuration,
    priorDuration,
    eoyInstant,
    boyInstant,
    reportYearFromCtx,
  };
}

/**
 * First non-empty string fact for concept (any context, prefer unsegmented).
 */
function getStringFact(doc, concept, preferredContextIds = []) {
  const list = doc.byConcept.get(concept) || [];
  if (!list.length) return "";

  for (const id of preferredContextIds) {
    const hit = list.find((f) => f.contextRef === id && f.value);
    if (hit) return hit.value;
  }

  // Prefer unsegmented contexts
  const unseg = list.find((f) => {
    const c = doc.contexts.get(f.contextRef);
    return f.value && c && !c.hasSegment;
  });
  if (unseg) return unseg.value;

  const any = list.find((f) => f.value);
  return any ? any.value : "";
}

/**
 * Numeric fact for concept in a specific context (or first unsegmented).
 */
function getNumericFact(doc, concept, contextId = null) {
  const list = doc.byConcept.get(concept) || [];
  if (!list.length) return null;

  if (contextId) {
    const hit = list.find((f) => f.contextRef === contextId);
    if (hit) return hit.numeric;
  }

  const unseg = list.find((f) => {
    const c = doc.contexts.get(f.contextRef);
    return c && !c.hasSegment && f.numeric != null;
  });
  if (unseg) return unseg.numeric;

  const any = list.find((f) => f.numeric != null);
  return any ? any.numeric : null;
}

/**
 * All facts for concept filtered by optional segment dimension.
 */
function getFactsForConcept(doc, concept, { requireSegment = null } = {}) {
  const list = doc.byConcept.get(concept) || [];
  return list.filter((f) => {
    const c = doc.contexts.get(f.contextRef);
    if (!c) return false;
    if (requireSegment === false && c.hasSegment) return false;
    if (requireSegment === true && !c.hasSegment) return false;
    return true;
  });
}

/**
 * Detect utility_id, report_year, respondent from XBRL.
 */
function detectXbrlMeta(doc, filePath = "") {
  const pref = [];
  if (doc.primaryDuration) pref.push(doc.primaryDuration.id);

  const utilityId =
    getStringFact(doc, "CompanyIdentifier", pref) ||
    getStringFact(doc, "RespondentIdentifier", pref) ||
    getStringFact(doc, "FilerIdentifier", pref) ||
    "";

  let reportYear = null;
  const yearRaw = getStringFact(doc, "ReportYear", pref);
  if (yearRaw) reportYear = Number(yearRaw);
  if (reportYear == null || Number.isNaN(reportYear)) {
    reportYear = doc.reportYearFromCtx;
  }
  if (reportYear == null || Number.isNaN(reportYear)) {
    const base = path.basename(filePath || doc.filePath, path.extname(filePath || doc.filePath));
    const ym = base.match(/(19|20)\d{2}/);
    if (ym) reportYear = Number(ym[0]);
  }

  const respondent =
    getStringFact(doc, "RespondentLegalName", pref) ||
    getStringFact(doc, "EntityName", pref) ||
    "";

  return {
    utilityId,
    reportYear: Number.isFinite(reportYear) ? reportYear : null,
    respondent,
  };
}

/**
 * Company folder name from XBRL meta + filename.
 */
function detectCompanyFromXbrl(doc, filePath) {
  const meta = detectXbrlMeta(doc, filePath);
  return companyFolderName(meta.respondent, "", filePath);
}

/**
 * Group dimensional facts by segment member key for a given axis-like dimension name.
 * Returns Map<memberKey, { contextId, facts: Map<concept, fact> }>
 */
function groupBySegmentMember(doc, dimensionNameHint) {
  const hint = (dimensionNameHint || "").toLowerCase();
  const groups = new Map();

  for (const [id, ctx] of doc.contexts) {
    if (!ctx.hasSegment) continue;
    const seg =
      ctx.segments.find((s) =>
        s.dimension.toLowerCase().includes(hint)
      ) || ctx.segments[0];
    if (!seg) continue;
    const key = seg.member || seg.raw;
    if (!groups.has(key)) {
      groups.set(key, { contextId: id, member: key, dimension: seg.dimension, facts: new Map() });
    }
  }

  // Attach facts
  for (const f of doc.facts) {
    const ctx = doc.contexts.get(f.contextRef);
    if (!ctx || !ctx.hasSegment) continue;
    const seg =
      ctx.segments.find((s) =>
        s.dimension.toLowerCase().includes(hint)
      ) || ctx.segments[0];
    if (!seg) continue;
    const key = seg.member || seg.raw;
    if (!groups.has(key)) {
      groups.set(key, {
        contextId: f.contextRef,
        member: key,
        dimension: seg.dimension,
        facts: new Map(),
      });
    }
    const g = groups.get(key);
    // Prefer matching context
    if (g.contextId === f.contextRef || !g.facts.has(f.concept)) {
      g.facts.set(f.concept, f);
    }
  }

  return groups;
}

module.exports = {
  decodeXmlEntities,
  parseNumber,
  parseContexts,
  parseFacts,
  loadXbrl,
  getStringFact,
  getNumericFact,
  getFactsForConcept,
  detectXbrlMeta,
  detectCompanyFromXbrl,
  groupBySegmentMember,
};

/**
 * Company folder detection and resolution for FERC Form 1 pipeline.
 */

const fs = require("fs");
const path = require("path");

function cleanText(s) {
  return String(s || "")
    .replace(/&amp;/g, "&")
    .replace(/&nbsp;/g, " ")
    .replace(/&#160;/g, " ")
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)))
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/\s+/g, " ")
    .trim();
}

/**
 * Ordered company aliases (first match wins).
 * More specific Entergy entities before generic "Entergy".
 */
const COMPANY_ALIASES = [
  { test: /entergy\s+new\s+orleans/i, name: "ENTERGY NOLA" },
  { test: /entergy\s+louisiana/i, name: "ENTERGY LA" },
  { test: /\bcleco\b/i, name: "CLECO" },
  { test: /\bswepco\b|southwestern\s+electric\s+power/i, name: "SWEPCO" },
  { test: /\bentergy\b/i, name: "ENTERGY" },
];

/**
 * Map respondent / title / filename → short company folder name.
 */
function companyFolderName(respondent, title = "", filePath = "") {
  const LEGAL =
    /\b(LLC|L\.?L\.?C\.?|Inc\.?|Incorporated|Corp\.?|Corporation|Company|Co\.|Ltd\.?|Limited|LP|L\.P\.|PLC)\b/gi;
  const GENERIC =
    /^(Power|Electric|Electrical|Energy|Utility|Utilities|Gas|Transmission|Service|Services|Holding|Holdings|Group|of|and|the|d\/b\/a|New|Orleans|Louisiana)$/i;

  const sources = [
    respondent,
    title,
    path.basename(filePath, path.extname(filePath)),
  ]
    .map((s) => cleanText(s))
    .filter(Boolean);

  for (const src of sources) {
    for (const a of COMPANY_ALIASES) {
      if (a.test.test(src)) return a.name;
    }
  }

  let raw = sources[0] || "UNKNOWN";
  if (!/\s/.test(raw) && /[a-z][A-Z]/.test(raw)) {
    raw = raw
      .replace(/([a-z])([A-Z])/g, "$1 $2")
      .replace(/([A-Za-z])(\d+)/g, "$1")
      .trim();
  }
  raw = raw.replace(LEGAL, " ").replace(/[,\.]/g, " ");
  const words = raw.split(/\s+/).filter((w) => w && !GENERIC.test(w));
  const brand = words[0] || sources[0] || "UNKNOWN";
  return brand.replace(/[^A-Za-z0-9 _-]/g, "").trim().toUpperCase() || "UNKNOWN";
}

/**
 * Reuse existing company folder (case-insensitive); create only if missing.
 */
function resolveCompanyDir(baseDir, companyShortName) {
  const desired = companyShortName || "UNKNOWN";
  fs.mkdirSync(baseDir, { recursive: true });
  const entries = fs.readdirSync(baseDir, { withFileTypes: true });
  const existing = entries.find(
    (e) => e.isDirectory() && e.name.toLowerCase() === desired.toLowerCase()
  );
  if (existing) {
    return {
      companyDir: path.join(baseDir, existing.name),
      company: existing.name,
      created: false,
    };
  }
  const companyDir = path.join(baseDir, desired);
  fs.mkdirSync(companyDir, { recursive: true });
  return { companyDir, company: desired, created: true };
}

/**
 * Resolve a template path: prefer templates/<name>, then root/<name>.
 */
function resolveTemplatePath(baseDir, templateName) {
  const candidates = [
    path.join(baseDir, "templates", templateName),
    path.join(baseDir, templateName),
  ];
  for (const c of candidates) {
    if (fs.existsSync(c)) return c;
  }
  return candidates[0];
}

module.exports = {
  cleanText,
  COMPANY_ALIASES,
  companyFolderName,
  resolveCompanyDir,
  resolveTemplatePath,
};

/**
 * Cross-platform XLSX pack/unpack and cell helpers.
 * Uses system zip/unzip (macOS/Linux) or PowerShell (Windows).
 */

const fs = require("fs");
const path = require("path");
const os = require("os");
const { execSync } = require("child_process");

function xmlEscape(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

/**
 * Set or replace a cell value in sheet XML, preserving style when present.
 */
function setCellValue(sheetXml, ref, value, { asString = false } = {}) {
  const cellRe = new RegExp(`<c r="${ref}"([^>/]*)(?:/>|>([\\s\\S]*?)</c>)`);
  const m = sheetXml.match(cellRe);

  if (value === null || value === undefined || value === "") {
    if (!m) return sheetXml;
    let attrs = m[1] || "";
    attrs = attrs.replace(/\s*t="[^"]*"/g, "");
    return sheetXml.replace(cellRe, `<c r="${ref}"${attrs}/>`);
  }

  const writeAsString = asString || typeof value === "string";

  if (m) {
    let attrs = m[1] || "";
    attrs = attrs.replace(/\s*t="[^"]*"/g, "");
    if (writeAsString) {
      return sheetXml.replace(
        cellRe,
        `<c r="${ref}"${attrs} t="inlineStr"><is><t>${xmlEscape(
          String(value)
        )}</t></is></c>`
      );
    }
    return sheetXml.replace(
      cellRe,
      `<c r="${ref}"${attrs}><v>${value}</v></c>`
    );
  }

  const rowNum = ref.replace(/^[A-Z]+/, "");
  const rowRe = new RegExp(`(<row r="${rowNum}"[^>]*>)([\\s\\S]*?)(</row>)`);
  if (!sheetXml.match(rowRe)) {
    throw new Error(`Row ${rowNum} not found for cell ${ref}`);
  }
  const newCell = writeAsString
    ? `<c r="${ref}" t="inlineStr"><is><t>${xmlEscape(
        String(value)
      )}</t></is></c>`
    : `<c r="${ref}"><v>${value}</v></c>`;
  return sheetXml.replace(rowRe, `$1$2${newCell}$3`);
}

function hasCmd(cmd) {
  try {
    execSync(
      process.platform === "win32" ? `where ${cmd}` : `command -v ${cmd}`,
      { stdio: "pipe" }
    );
    return true;
  } catch {
    return false;
  }
}

/**
 * Unpack an xlsx (zip) into a directory.
 */
function unpackXlsx(xlsxPath, destDir) {
  fs.mkdirSync(destDir, { recursive: true });
  const absXlsx = path.resolve(xlsxPath);
  const absDest = path.resolve(destDir);

  if (process.platform === "win32" && !hasCmd("unzip")) {
    execSync(
      `powershell -NoProfile -Command "Expand-Archive -LiteralPath '${absXlsx.replace(
        /'/g,
        "''"
      )}' -DestinationPath '${absDest.replace(/'/g, "''")}' -Force"`,
      { stdio: "pipe" }
    );
    return;
  }

  execSync(`unzip -q -o "${absXlsx}" -d "${absDest}"`, { stdio: "pipe" });
}

/**
 * Pack a directory into an xlsx (zip) file.
 */
function packXlsx(sourceDir, outputPath) {
  const absSrc = path.resolve(sourceDir);
  const absOut = path.resolve(outputPath);
  fs.mkdirSync(path.dirname(absOut), { recursive: true });
  if (fs.existsSync(absOut)) fs.unlinkSync(absOut);

  if (process.platform === "win32" && !hasCmd("zip")) {
    const ps1 = path.join(os.tmpdir(), `zip_xlsx_${Date.now()}.ps1`);
    fs.writeFileSync(
      ps1,
      [
        "Add-Type -AssemblyName System.IO.Compression.FileSystem",
        `if (Test-Path -LiteralPath '${absOut.replace(/'/g, "''")}') { Remove-Item -LiteralPath '${absOut.replace(/'/g, "''")}' -Force }`,
        `[System.IO.Compression.ZipFile]::CreateFromDirectory('${absSrc.replace(/'/g, "''")}', '${absOut.replace(/'/g, "''")}', [System.IO.Compression.CompressionLevel]::Optimal, $false)`,
      ].join("\r\n")
    );
    try {
      execSync(`powershell -NoProfile -ExecutionPolicy Bypass -File "${ps1}"`, {
        stdio: "pipe",
      });
    } finally {
      try {
        fs.unlinkSync(ps1);
      } catch {
        /* ignore */
      }
    }
    return;
  }

  // zip contents of directory (not the directory itself)
  execSync(`cd "${absSrc}" && zip -qr "${absOut}" .`, { stdio: "pipe" });
}

/**
 * Copy template xlsx, yield unpacked dir, pack to output when done.
 * @returns {{ unpacked: string, tmp: string, finish: (outputPath: string) => void, cleanup: () => void }}
 */
function openTemplateCopy(templatePath) {
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), "ferc-xlsx-"));
  const zipCopy = path.join(tmp, "book.xlsx");
  const unpacked = path.join(tmp, "out");
  fs.copyFileSync(templatePath, zipCopy);
  unpackXlsx(zipCopy, unpacked);

  return {
    tmp,
    unpacked,
    finish(outputPath) {
      packXlsx(unpacked, outputPath);
    },
    cleanup() {
      fs.rmSync(tmp, { recursive: true, force: true });
    },
  };
}

/**
 * Optionally rename the first sheet in workbook.xml.
 */
function setSheetName(unpackedDir, sheetName) {
  if (!sheetName) return;
  const wbPath = path.join(unpackedDir, "xl", "workbook.xml");
  let wb = fs.readFileSync(wbPath, "utf8");
  if (!wb.includes(`name="${sheetName}"`)) {
    wb = wb.replace(
      /(<sheet\s+name=")[^"]+(")/,
      `$1${sheetName.replace(/"/g, "")}$2`
    );
    fs.writeFileSync(wbPath, wb, "utf8");
  }
}

module.exports = {
  xmlEscape,
  setCellValue,
  unpackXlsx,
  packXlsx,
  openTemplateCopy,
  setSheetName,
};
